parameters.jsCode:
const raw = $('Claude — Qualify & Score Lead').first().json.text;
const match = raw.match(/\{[\s\S]*\}/);
const parsed = match ? JSON.parse(match[0]) : { qualified: false, recommended_next: 'nurture', score: 0 };
const lead = $('Webhook — Incoming Lead').first().json;
return [{ json: { ...lead, ...parsed, received_at: new Date().toISOString() } }];

